// TestBenchmarkCellLifecycleWritesReport verifies that a sequential run writes
// cell-state.json before execution, invokes adapter and executor with JSON stdin
// contracts, writes result.json/report.json, and removes cell-state.json after
// terminal completion.
func TestBenchmarkCellLifecycleWritesReport(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := os.Stat(benchmarkScript); err != nil {
		t.Fatalf("benchmark script not found: %v", err)
	}

	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	tmpDir := t.TempDir()

	// Run with noop profile and canary bench-set
	cmd := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--jobs", "1",
		"--out", tmpDir)
	cmd.Dir = benchDir

	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		t.Fatalf("benchmark run failed: %v\nstderr: %s", err, stderr.String())
	}

	// Find a cell directory
	cellsDir := filepath.Join(tmpDir, "cells")
	var cellDir string
	filepath.Walk(cellsDir, func(path string, info os.FileInfo, err error) error {
		if err == nil && info.Name() == "report.json" {
			cellDir = filepath.Dir(path)
		}
		return nil
	})

	if cellDir == "" {
		t.Fatalf("no cell directory with report.json found")
	}

	// Verify report.json exists and is valid JSON
	reportPath := filepath.Join(cellDir, "report.json")
	reportData, err := os.ReadFile(reportPath)
	if err != nil {
		t.Fatalf("failed to read report.json: %v", err)
	}

	var report map[string]interface{}
	if err := json.Unmarshal(reportData, &report); err != nil {
		t.Fatalf("report.json is not valid JSON: %v", err)
	}

	// Verify required fields in report
	requiredFields := []string{"cell_id", "task_id", "framework", "dataset", "final_status"}
	for _, field := range requiredFields {
		if _, ok := report[field]; !ok {
			t.Errorf("report.json missing required field: %s", field)
		}
	}

	// Verify cell-state.json does NOT exist (should be removed after completion)
	stateFile := filepath.Join(cellDir, "cell-state.json")
	if _, err := os.Stat(stateFile); err == nil {
		t.Errorf("cell-state.json should be removed after completion but still exists")
	} else if !os.IsNotExist(err) {
		t.Fatalf("unexpected error checking cell-state.json: %v", err)
	}

	// Verify result.json exists (created by executor)
	resultPath := filepath.Join(cellDir, "result.json")
	if _, err := os.Stat(resultPath); err != nil {
		t.Logf("result.json not found (may be expected if executor didn't create it): %v", err)
	}
}

// TestBenchmarkResumeSkipsTerminalReport verifies that default run mode skips a cell
// whose report.json contains a terminal final_status.
func TestBenchmarkResumeSkipsTerminalReport(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := os.Stat(benchmarkScript); err != nil {
		t.Fatalf("benchmark script not found: %v", err)
	}

	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	tmpDir := t.TempDir()

	// First run to create cells
	cmd := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--jobs", "1",
		"--out", tmpDir)
	cmd.Dir = benchDir
	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		t.Fatalf("first run failed: %v\nstderr: %s", err, stderr.String())
	}

	// Count initial reports
	var initialReports []string
	filepath.Walk(tmpDir, func(path string, info os.FileInfo, err error) error {
		if err == nil && info.Name() == "report.json" {
			initialReports = append(initialReports, path)
		}
		return nil
	})

	if len(initialReports) == 0 {
		t.Fatalf("no reports created in first run")
	}

	// Get modification time of first report
	firstReportInfo, err := os.Stat(initialReports[0])
	if err != nil {
		t.Fatalf("failed to stat first report: %v", err)
	}
	firstModTime := firstReportInfo.ModTime()

	// Small delay to ensure timestamp difference is detectable
	time.Sleep(100 * time.Millisecond)

	// Second run (resume) - should skip terminals
	cmd = exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--jobs", "1",
		"--out", tmpDir)
	cmd.Dir = benchDir
	stderr.Reset()
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		t.Fatalf("second run (resume) failed: %v\nstderr: %s", err, stderr.String())
	}

	// Verify "skip" message appears in stderr for skipped cells
	stderrStr := stderr.String()
	if !strings.Contains(stderrStr, "skip") {
		t.Logf("warning: expected 'skip' in stderr during resume")
	}

	// Verify reports were not modified (skipped)
	for _, reportPath := range initialReports {
		info, err := os.Stat(reportPath)
		if err != nil {
			t.Fatalf("failed to stat report: %v", err)
		}
		if info.ModTime().After(firstModTime) {
			t.Errorf("report was modified during resume, expected skip: %s", reportPath)
		}
	}
}

