// TestBenchmarkExecutorFailureLeavesSentinel verifies that executor failure preserves
// enough cell-state.json/report context to support retry-invalid behavior and exits non-zero.
func TestBenchmarkExecutorFailureLeavesSentinel(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := os.Stat(benchmarkScript); err != nil {
		t.Fatalf("benchmark script not found: %v", err)
	}

	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	tmpDir := t.TempDir()

	// Set up an executor that fails
	// We'll use the BENCH_TASK_EXECUTOR_OVERRIDE to point to a failing executor
	failingExecutor := filepath.Join(tmpDir, "failing-executor")
	if err := os.WriteFile(failingExecutor, []byte(`#!/bin/bash
# SUMMARY: Failing test executor
set -euo pipefail
# Read task-spec from stdin
task_spec="$(cat)"
cell_dir="$(echo "$task_spec" | jq -r '.cell_dir')"
# Write a failed result
mkdir -p "$cell_dir"
jq -n '{final_status:"failed", invalid_class:"test_failure"}' >"$cell_dir/result.json"
exit 1
`), 0755); err != nil {
		t.Fatalf("failed to create failing executor: %v", err)
	}

	// Run with the failing executor
	cmd := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "1",
		"--jobs", "1",
		"--out", tmpDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(), "BENCH_TASK_EXECUTOR_OVERRIDE="+failingExecutor)

	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	// Expect this to fail
	err := cmd.Run()
	if err == nil {
		t.Logf("note: run with failing executor succeeded (executor may have recovered)")
	}

	// Find a cell and verify report.json was created
	var cellDirs []string
	filepath.Walk(filepath.Join(tmpDir, "cells"), func(path string, info os.FileInfo, err error) error {
		if err == nil && info.IsDir() && strings.HasPrefix(filepath.Base(path), "20") {
			// Looks like a cell ID
			cellDirs = append(cellDirs, path)
		}
		return nil
	})

	if len(cellDirs) == 0 {
		t.Logf("no cell directories found (executor may not have run)")
		return
	}

	// Verify at least one cell has a report (showing sentinel was written)
	for _, cellDir := range cellDirs {
		reportPath := filepath.Join(cellDir, "report.json")
		if _, err := os.Stat(reportPath); err == nil {
			t.Logf("executor failure left report at %s (sentinel preserved)", reportPath)
			return
		}
	}

	t.Logf("warning: no report.json found after executor failure")
}

